import {useState} from 'react';

function Square() {
  const [value, setValue]=useState(null);
  function handleClick(){
    setValue('X');
  }
  return (
      <button
          className="square"
          onClick={handleClick}
      >
        {value}
      </button>
  );
}

export default function Board() {
  const [squares, setSquares] = useState(Array(9).fill(null));
  return (
      <>
        <div className="board-row">
            <Square value={stuares[0]}/>
            <Square value={stuares[1]}/>
            <Square value={stuares[2]}/>
          </div>
          <div className="board-row">
            <Square value={stuares[3]}/>
            <Square value={stuares[4]}/>
            <Square value={stuares[5]}/>
          </div>
          <div className="board-row">
            <Square value={stuares[6]}/>
            <Square value={stuares[7]}/>
            <Square value={stuares[8]}/>
          </div>

        </>
  );
}
